SELECT vhd_id, vhd_name
FROM vhds
WHERE compression_enabled = 1;

SELECT t.type_name, s.size_name, s.max_capacity
FROM vhd_types t
CROSS JOIN vhd_sizes s;

SELECT COUNT(vhd_id)
FROM vhds
WHERE owner_id = (SELECT user_id FROM users WHERE email = 'alice.johnson@example.com');

SELECT size 
FROM vhd_snapshots 
WHERE size = (SELECT MAX(size) FROM vhd_snapshots);

SELECT vhd_id
FROM vhds
WHERE owner_id = (SELECT user_id FROM users WHERE user_name = 'Alice Johnson');

SELECT AVG(CAST(REPLACE(storage_size, 'MB', '') AS REAL) * 1024 * 1024) AS avg_size_in_bytes
FROM vhd_storage
WHERE storage_type = 'SSD';

SELECT COUNT(vhd_id) AS total_vhds
FROM vhds
WHERE STRFTIME('%Y', creation_date) = '2023' AND deduplication_enabled = 1;

SELECT vhds.vhd_name, vhd_sizes.size_name 
FROM vhds
JOIN vhd_sizes ON vhds.size = vhd_sizes.size_id;

SELECT SUM(size) AS total_size
FROM vhd_snapshots
WHERE vhd_id = 0;

SELECT size
FROM vhd_snapshots
WHERE vhd_id = (SELECT vhd_id FROM vhds WHERE vhd_name = 'dynamic_50.vhd');

SELECT DISTINCT md5hash
FROM vhds
WHERE md5hash IS NOT NULL;
